INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (100101, "A", "人助け、応援", "トゥインクルウィッシュ", 2, 8, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", "人助けが大好き！　前向き格闘娘", 155, 16, 0, "獣人族", 27, "ヒヨリ", 44, "東山奈央");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (100201, "O", "料理、人間観察", "トゥインクルウィッシュ", 2, 4, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", "戦闘のサポートが得意な、心優しい少女", 158, 17, 0, "ヒューマン", 5, "ユイ", 47, "種田梨沙");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (100301, "B", "読書、乗馬、お茶", "トゥインクルウィッシュ", 2, 1, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", "クールで何事にも真っ直ぐな剣士", 163, 18, 0, "魔族", 12, "レイ", 46, "早見沙織");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (100401, "O", "いたずら、探検", "リトルリリカル", 5, 8, "イタズラなら任せて！\nにいちゃん、引っかからないように気を付けなよー♪", "探検好きのイタズラっ子", 128, 9, 0, "ヒューマン", 10, "ミソギ", 27, "諸星すみれ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (100501, "O", "ヒーローごっこ", "王宮騎士団（NIGHTMARE）", 8, 11, "？？？", "ヒーローに憧れる騎士見習いの少女", 146, 12, 0, "獣人族", 25, "マツリ", 40, "下田麻美");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (100601, "O", "サックス", "悪魔偽王国軍（ディアボロス）", 7, 11, "アカリ、まだわからないことが多くて…\nだからこれから\nいろいろ教えてくださいね、お兄ちゃん！", "甘え上手なみんなの人気者", 150, 13, 0, "魔族", 22, "アカリ", 42, "浅倉杏美");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (100701, "B", "プリンを食べること", "悪魔偽王国軍（ディアボロス）", 7, 1, "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", "プリン大好きゴースト娘", 130, 14, 0, "魔族", 23, "ミヤコ", 32, "雨宮天");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (100801, "AB", "鏡で自分を見ること", "ヴァイスフリューゲル　ランドソル支部", 15, 10, "ボクって本当に美しいなあ…\n可愛くて美しいなんて本当に罪だと思うけど\n生まれもったものだから仕方ないんだ♪", "ボクは誰よりも美しい", 150, 14, 0, "エルフ", 10, "ユキ", 40, "大空直美");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (100901, "A", "小説執筆", "トワイライトキャラバン", 13, 7, "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！", "前世を信じる中二病患者、「疾風の冥姫」", 159, 17, 0, "魔族", 5, "アンナ", 45, "髙野麻美");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (101001, "O", "空想、ぬいぐるみ集め", "自警団（カォン）", 10, 9, "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", "マホマホ王国のプリンセス", 155, 16, 0, "獣人族", 22, "マホ", 42, "内田真礼");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (101101, "A", "お裁縫", "ラビリンス", 3, 8, "覚えていないと思うんですけど…\n私は妹なんですよ！\nだからお兄ちゃんって呼んでいいですか？", "人懐っこくてマシンガントークな妹系少女", 156, 15, 0, "ヒューマン", 25, "リノ", 44, "阿澄佳奈");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (101201, "A", "妹と遊ぶこと、二度寝、昼寝、早寝", "フォレスティエ", 6, 12, "私はハツネ！　困っている人の味方だよ！\n困った時は、いつでも言ってね♪\n私のちょ…ま、魔法で助けてあげるから！", "みんなのために超能力を使う眠り姫", 156, 17, 0, "エルフ", 24, "ハツネ", 46, "大橋彩香");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (101301, "O", "読書、魔法", "トワイライトキャラバン", 13, 8, "", "オタク全開な魔法少女", 166, 18, 0, "魔族", 21, "ナナカ", 55, "佳村はるか");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (101401, "AB", "読書、推理", "自警団（カォン）", 10, 11, "test", "頭脳明晰な美少女名探偵", 152, 15, 0, "獣人族", 3, "カスミ", 41, "水瀬いのり");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (101501, "O", "絵本作り", "フォレスティエ", 6, 9, "test", "母性溢れる優しいみんなの「ミサト先生」", 165, 21, 0, "エルフ", 5, "ミサト", 54, "國府田マリ子");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (101601, "O", "ファッション", "ルーセント学院", 14, 4, "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", "天真爛漫で人気者のカリスマモデル", 167, 17, 0, "魔族", 10, "スズナ", 48, "上坂すみれ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (101701, "A", "踊り、空手", "自警団（カォン）", 10, 7, "ハイターイ！　歌って踊って、\n最高に盛り上がるさ～！\nやさやさ、キミも一緒に踊るさ～！", "いつでも「なんくるないさ～」な天然娘", 158, 17, 0, "獣人族", 7, "カオリ", 53, "高森奈津美");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (101801, "B", "恋愛小説、恋愛舞台、恋愛漫画の鑑賞", "ルーセント学院", 14, 8, "いつも助けてくれてありがとう\n私のほうが年上なのに\n頼ってばかりでごめんなさい～", "多くの男性を魅了する無垢な女教師", 162, 23, 0, "魔族", 14, "イオ", 52, "伊藤静");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (102001, "O", "かわいいもの集め", "リトルリリカル", 5, 4, "ぴょんぴょん、うさぎさんになりたいな～♪　\nミミ、うさぎさんになれたら、\n最初におにいちゃんに見せてあげるね！", "お歌もにんじんも、ウサギさんも大好き♪", 117, 10, 0, "獣人族", 3, "ミミ", 21, "日高里菜");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (102101, "B", "観劇、おままごと", "サレンディア救護院", 9, 6, "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", "泣き虫で臆病な守ってあげたい女の子", 150, 12, 0, "ヒューマン", 9, "クルミ", 40, "植田佳奈");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (102201, "O", "ゲーム全般", "悪魔偽王国軍（ディアボロス）", 7, 11, "え、えっと…こ、こういうときって、\nどういうことを言えばいいんだっけ…\nうう、どうしてちゃんと喋れないの…", "人見知りであまのじゃくな女の子", 150, 13, 0, "魔族", 22, "ヨリ", 40, "原紗友里");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (102301, "B", "屋内でできる遊び", "サレンディア救護院", 9, 5, "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", "ぷうきちといつも一緒！", 148, 14, 0, "ヒューマン", 10, "アヤネ", 38, "芹澤優");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (102501, "O", "ご奉仕", "サレンディア救護院", 9, 12, "うぅ…ごめんなさい～…\nまたキッチンを爆発させてしまいました～\nこれじゃあメイド失格です…", "お嬢さまのためにがんばるドジっ娘メイド", 154, 15, 0, "ヒューマン", 12, "スズメ", 43, "悠木碧");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (102601, "B", "あんパン", "牧場（エリザベスパーク）", 11, 1, "test", "遊びと睡眠が何より大事なぐうたら娘", 144, 17, 0, "獣人族", 1, "リン", 42, "小岩井ことり");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (102701, "B", "実験、裁縫、料理", "トワイライトキャラバン", 13, 7, "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", "運命の相手に一途すぎる乙女", 154, 16, 0, "魔族", 30, "エリコ", 43, "橋本ちなみ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (102801, "A", "経営、お茶会", "サレンディア救護院", 9, 10, "貧乏性？　いいえ、\n「もったいない」の精神で\n日々を過ごしてるだけよ！", "救護院を経営する優しい庶民派お嬢様", 156, 17, 0, "エルフ", 4, "サレン", 43, "堀江由衣");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (102901, "B", "舞台鑑賞、ダンス", "カルミナ", 4, 1, "いつか世界中の人達をファンにしてみせる！\nトップアイドルになるその日まで、\n応援よろしくね♪", "歌って踊れる大人気アイドル", 157, 17, 0, "ヒューマン", 24, "ノゾミ", 40, "日笠陽子");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (103001, "O", "忍法開発", "ヴァイスフリューゲル　ランドソル支部", 15, 8, "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", "トーゴクの神秘、オシエテクダサイ！", 163, 16, 0, "ヒューマン", 31, "ニノン", 51, "佐藤聡美");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (103101, "AB", "占い", "悪魔偽王国軍（ディアボロス）", 7, 12, "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", "占いが得意な霊能少女", 157, 18, 0, "魔族", 22, "シノブ", 42, "大坪由佳");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (103201, "AB", "慈善事業", "メルクリウス財団", 12, 3, "この私とともにいる限り、\nお金に不自由はさせませんわ！", "一人前の商人を目指すパワフルお嬢様", 157, 18, 0, "ヒューマン", 12, "アキノ", 45, "松嵜麗");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (103301, "B", "漫才", "牧場（エリザベスパーク）", 11, 3, "オラはどんな時でもみんなに笑顔を届ける\n最高の芸人目指してる！\n一緒に頑張るべ！", "みんなを笑顔にするお笑い牧場主", 142, 20, 0, "ヒューマン", 3, "マヒル", 35, "新田恵海");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (103401, "A", "ウインドーショッピング", "メルクリウス財団", 12, 3, "キミには情けないところばかり\n見られているけど、こんなところ、\nキミ以外には見せないんだからね？", "純情でほっとけない大人の女性", 164, 22, 0, "エルフ", 16, "ユカリ", 55, "今井麻美");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (103601, "A", "お勉強", "リトルリリカル", 5, 2, "test", "礼儀正しくしっかり者のちびっ子優等生", 118, 8, 0, "エルフ", 2, "キョウカ", 21, "小倉唯");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (103701, "A", "剣術、年長者をからかう", "王宮騎士団（NIGHTMARE）", 8, 8, "test", "義理堅くてからかい好きな剣術少女", 149, 13, 0, "ヒューマン", 11, "トモ", 43, "茅原実里");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (103801, "A", "読書、お散歩", "牧場（エリザベスパーク）", 11, 11, "ゴホッ、ゴホッ…か、身体は弱いけど、\nせめて気持ちだけでも前向きに…！\nあっ、でもダメ…立ちくらみが…", "読書が趣味の病弱少女", 153, 14, 0, "獣人族", 3, "シオリ", 40, "小清水亜美");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (104001, "AB", "友達作りのイメトレ", "フォレスティエ", 6, 6, "友達ができるその日まで…\nBB団で\nトレーニングですっ！", "「友達」に憧れる、エルフの森の女の子", 158, 13, 0, "エルフ", 6, "アオイ", 44, "花澤香菜");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (104201, "O", "各種楽器", "カルミナ", 4, 6, "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", "人々を守るために歌う、唱喚士の少女", 163, 17, 0, "ヒューマン", 3, "チカ", 46, "福原綾香");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (104301, "O", "お菓子作り", "自警団（カォン）", 10, 8, "腹へってたら言えよな\n簡単でよければ\nすっげー旨いもん食わせてやるよ！", "男勝りで情に厚いワイルド娘", 168, 17, 0, "獣人族", 9, "マコト", 54, "小松未可子");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (104401, "A", "世界征服", "悪魔偽王国軍（ディアボロス）", 7, 5, "test", "かつては夜を支配した最強の吸血鬼", 172, "??", 0, "魔族", 5, "イリヤ", 50, "丹下桜");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (104501, "AB", "小説を読むこと", "ヴァイスフリューゲル　ランドソル支部", 15, 11, "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", "妄想大好き！　ほんとは照れ屋な女の子", 157, 18, 0, "ヒューマン", 19, "クウカ", 49, "長妻樹里");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (104601, "AB", "猫とたわむれること", "メルクリウス財団", 12, 3, "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", "弱きを助け強きをくじく猫娘", 158, 19, 0, "獣人族", 1, "タマキ", 48, "沼倉愛美");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (104701, "A", "格闘技、湯浴み", "王宮騎士団（NIGHTMARE）", 8, 10, "？？？", "素顔を見せない冷静沈着な女性騎士", 171, 25, 0, "ヒューマン", 25, "ジュン", 50, "川澄綾子");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (104801, "O", "傭兵などのアルバイト", "メルクリウス財団", 12, 11, "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", "仕事も私事も効率優先な傭兵少女", 163, 20, 0, "ヒューマン", 11, "ミフユ", 49, "田所あずさ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (104901, "O", "家事全般", "ラビリンス", 3, 10, "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", "お姉ちゃんがお世話してあげるからねっ！", 168, 18, 0, "ヒューマン", 24, "シズル", 54, "生天目仁美");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (105001, "A", "ファッション誌鑑賞、コスメ集め", "ルーセント学院", 14, 1, "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", "ちょっとおませな恋に恋する女の子", 120, 11, 0, "魔族", 3, "ミサキ", 22, "久野美咲");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (105101, "A", "研究、実験", "トワイライトキャラバン", 13, 3, "私は科学者だけど、\n医者の真似事もしてるの\n病気になったら診てあげるわ", "実験が趣味の危険な科学者", 166, 27, 0, "ヒューマン", 7, "ミツキ", 53, "三石琴乃");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (105201, "A", "毛繕い、お喋り", "牧場（エリザベスパーク）", 11, 3, "私、ごく普通の、どこにでもいる女の子よ！\nみ、見た目以外はね…", "乙女チックなもふもふアニマル", 150, 17, 0, "獣人族", 14, "リマ", 100, "徳井青空");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (105301, "A", "お菓子屋通い", "ヴァイスフリューゲル　ランドソル支部", 15, 7, "「白き翼」こと、ヴァイスフリューゲル…\nその名に恥じぬよう、天高く舞い、\n華麗に敵を倒してみせる！", "見た目も中身もお子ちゃまな異国の軍人", 140, 17, 0, "ヒューマン", 28, "モニカ", 33, "辻あゆみ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (105401, "AB", "裁縫", "カルミナ", 4, 9, "test", "ファッション大好きなキュートガール", 153, 14, 0, "ヒューマン", 7, "ツムギ", 45, "木戸衣吹");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (105501, "O", "観察", "ヴァイスフリューゲル　ランドソル支部", 15, 4, "test", "どこまでも一途に慕う、純情乙女", 155, 16, 0, "エルフ", 7, "アユミ", 43, "大関英里");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (105601, "B", "釣り", "トワイライトキャラバン", 13, 7, "test", "人情味溢れる粋でいなせな「姉御」", 167, 25, 0, "ヒューマン", 11, "ルカ", 54, "佐藤利奈");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (105701, "O", "冒険、おしゃべり", "？？？", "", 3, "私ね、一人前の騎空士になりたいんだ\nいつか父さんみたいな騎空士になって、\n空の果てまで旅する。それが私の夢だよ！", "空への冒険を夢見る騎空士の少女", 156, 17, 0, "ヒューマン", 10, "ジータ", 45, "金元寿子");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (105801, "O", "食べ歩き、料理", "美食殿", 1, 3, "あ、あの…何か食べ物持っていませんか？\nもう、お腹ペコペコで…", "いつも元気な腹ペコ少女", 156, 17, 0, "ヒューマン", 31, "ペコリーヌ", 46, "M・A・O");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (105901, "B", "瞑想、動植物の飼育", "美食殿", 1, 5, "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", "主を慕う、小さなガイド役", 140, 11, 0, "エルフ", 11, "コッコロ", 35, "伊藤美来");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (106001, "A", "猫と遊ぶ", "美食殿", 1, 9, "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", "行き倒れの謎のネコミミ魔法使い", 152, 14, 0, "獣人族", 2, "キャル", 39, "立花理香");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (106101, "O", "冒険、思い出話", "？？？", "", 8, "いいんだ、アタシは……独りでも。大丈夫だから、もう慣れたからさぁ", "さまよえる謎の少女", 148, 16, 0, "ヒューマン", 11, "ムイミ", 40, "潘めぐみ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (106301, "O", "キレイな葉っぱを集めること", "？？？", "", 6, "", "森番を目指すエルフの少女", 155, 15, 0, "エルフ", 17, "アリサ", 42, "優木かな");
