INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (107501, "O", "食べ歩き、料理", "美食殿", 1, 3, "あ、あの…何か食べ物持っていませんか？\nもう、お腹ペコペコで…", "いつも元気な腹ペコ少女", 156, 17, 0, "ヒューマン", 31, "ペコリーヌ（サマー）", 46, "M・A・O");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (107601, "B", "瞑想、動植物の飼育", "美食殿", 1, 5, "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", "主を慕う、小さなガイド役", 140, 11, 0, "エルフ", 11, "コッコロ（サマー）", 35, "伊藤美来");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (107701, "O", "ご奉仕", "サレンディア救護院", 9, 12, "うぅ…ごめんなさい～…\nまたキッチンを爆発させてしまいました～\nこれじゃあメイド失格です…", "お嬢さまのためにがんばるドジっ娘メイド", 154, 15, 0, "ヒューマン", 12, "スズメ（サマー）", 43, "悠木碧");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (107801, "A", "猫と遊ぶ", "美食殿", 1, 9, "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", "行き倒れの謎のネコミミ魔法使い", 152, 14, 0, "獣人族", 2, "キャル（サマー）", 39, "立花理香");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (107901, "AB", "猫とたわむれること", "メルクリウス財団", 12, 3, "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", "弱きを助け強きをくじく猫娘", 158, 19, 0, "獣人族", 1, "タマキ（サマー）", 48, "沼倉愛美");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (108001, "O", "傭兵などのアルバイト", "メルクリウス財団", 12, 11, "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", "仕事も私事も効率優先な傭兵少女", 163, 20, 0, "ヒューマン", 11, "ミフユ（サマー）", 49, "田所あずさ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (108101, "AB", "占い", "悪魔偽王国軍（ディアボロス）", 7, 12, "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", "占いが得意な霊能少女", 157, 18, 0, "魔族", 22, "シノブ（ハロウィン）", 42, "大坪由佳");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (108201, "B", "プリンを食べること", "悪魔偽王国軍（ディアボロス）", 7, 1, "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", "プリン大好きゴースト娘", 130, 14, 0, "魔族", 23, "ミヤコ（ハロウィン）", 32, "雨宮天");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (108301, "A", "ファッション誌鑑賞、コスメ集め", "ルーセント学院", 14, 1, "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", "ちょっとおませな恋に恋する女の子", 120, 11, 0, "魔族", 3, "ミサキ（ハロウィン）", 22, "久野美咲");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (108401, "O", "各種楽器", "カルミナ", 4, 6, "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", "人々を守るために歌う、唱喚士の少女", 163, 17, 0, "ヒューマン", 3, "チカ（クリスマス）", 46, "福原綾香");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (108501, "B", "観劇、おままごと", "サレンディア救護院", 9, 6, "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", "泣き虫で臆病な守ってあげたい女の子", 150, 12, 0, "ヒューマン", 9, "クルミ（クリスマス）", 40, "植田佳奈");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (108601, "B", "屋内でできる遊び", "サレンディア救護院", 9, 5, "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", "ぷうきちといつも一緒！", 148, 14, 0, "ヒューマン", 10, "アヤネ（クリスマス）", 38, "芹澤優");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (108701, "A", "人助け、応援", "トゥインクルウィッシュ", 2, 8, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", "人助けが大好き！　前向き格闘娘", 155, 16, 0, "獣人族", 27, "ヒヨリ（ニューイヤー）", 44, "東山奈央");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (108801, "O", "料理、人間観察", "トゥインクルウィッシュ", 2, 4, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", "戦闘のサポートが得意な、心優しい少女", 158, 17, 0, "ヒューマン", 5, "ユイ（ニューイヤー）", 47, "種田梨沙");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (108901, "B", "読書、乗馬、お茶", "トゥインクルウィッシュ", 2, 1, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", "クールで何事にも真っ直ぐな剣士", 163, 18, 0, "魔族", 12, "レイ（ニューイヤー）", 46, "早見沙織");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (109001, "B", "実験、裁縫、料理", "トワイライトキャラバン", 13, 7, "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", "運命の相手に一途すぎる乙女", 154, 16, 0, "魔族", 30, "エリコ（バレンタイン）", 43, "橋本ちなみ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (109101, "O", "家事全般", "ラビリンス", 3, 10, "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", "お姉ちゃんがお世話してあげるからねっ！", 168, 18, 0, "ヒューマン", 24, "シズル（バレンタイン）", 54, "生天目仁美");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (109201, "AB", "読書", "？？？", "", 12, "私はアン！一応、マナリア王国の\n第一王女だけど…あまりかしこまらないで、\n気軽に仲良くしてくれたら嬉しいな！", "英霊と契約を結んだマナリアの天才王女", 156, 17, 0, "ヒューマン", 1, "アン", 55, "日笠陽子");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (109301, "O", "食べること、眠ること", "？？？", "", 2, "ルゥはルゥですぅ！マナリア魔法学院に\n通ってるですぅ。あなたもルゥの\nお友だちになってくれるですか？", "マナリア魔法学院の新入生", 144, 16, 0, "ヒューマン", 4, "ルゥ", 45, "こやまきみこ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (109401, "B", "ピアノ", "？？？", "", 11, "私はグレア。竜と人、両方の血を\n受け継いでいるの…\nえっと…よ、よろしくね", "人を超越した力を有す心優しい竜姫", 167, 17, 0, "半人半竜", 3, "グレア", 67, "福原綾香");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (109501, "AB", "小説を読むこと", "ヴァイスフリューゲル　ランドソル支部", 15, 11, "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", "妄想大好き！　ほんとは照れ屋な女の子", 157, 18, 0, "ヒューマン", 19, "クウカ（オーエド）", 49, "長妻樹里");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (109601, "O", "忍法開発", "ヴァイスフリューゲル　ランドソル支部", 15, 8, "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", "トーゴクの神秘、オシエテクダサイ！", 163, 16, 0, "ヒューマン", 31, "ニノン（オーエド）", 51, "佐藤聡美");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (109701, "?", "演劇鑑賞、詩文", "？？？", "", 2, "", "鬼がかりの万能妹メイド", 154, 17, 0, "鬼族", 2, "レム", "??", "水瀬いのり");
