INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (115601, "O", "料理、人間観察", "トゥインクルウィッシュ", 2, 4, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", "戦闘のサポートが得意な、心優しい少女", 158, 17, 0, "ヒューマン", 5, "ユイ（儀装束）", 47, "種田梨沙");
