INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (116001, "O", "空想、ぬいぐるみ集め", "自警団（カォン）", 10, 9, "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", "マホマホ王国のプリンセス", 155, 16, 0, "獣人族", 22, "マホ（シンデレラ）", 42, "内田真礼");
