INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (116801, "AB", "猫とたわむれること", "メルクリウス財団", 12, 3, "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", "弱きを助け強きをくじく猫娘", 158, 19, 0, "獣人族", 1, "タマキ（作業服）", 48, "沼倉愛美");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (116901, "O", "傭兵などのアルバイト", "メルクリウス財団", 12, 11, "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", "仕事も私事も効率優先な傭兵少女", 163, 20, 0, "ヒューマン", 11, "ミフユ（作業服）", 49, "田所あずさ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (117001, "B", "実験、裁縫、料理", "トワイライトキャラバン", 13, 7, "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", "運命の相手に一途すぎる乙女", 154, 16, 0, "魔族", 30, "エリコ（サマー）", 43, "橋本ちなみ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (117101, "O", "家事全般", "ラビリンス", 3, 10, "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", "お姉ちゃんがお世話してあげるからねっ！", 168, 18, 0, "ヒューマン", 24, "シズル（サマー）", 54, "生天目仁美");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (117201, "B", "舞台鑑賞、ダンス", "カルミナ", 4, 1, "", "歌って踊れる大人気アイドル", 157, 17, 0, "ヒューマン", 24, "ノゾミ（サマー）", 40, "日笠陽子");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (117301, "O", "各種楽器", "カルミナ", 4, 6, "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", "人々を守るために歌う、唱喚士の少女", 163, 17, 0, "ヒューマン", 3, "チカ（サマー）", 46, "福原綾香");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (117401, "AB", "裁縫", "カルミナ", 4, 9, "", "ファッション大好きなキュートガール", 153, 14, 0, "ヒューマン", 7, "ツムギ（サマー）", 45, "木戸衣吹");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (117501, "A", "研究、実験", "トワイライトキャラバン", 13, 3, "私は科学者だけど、\n医者の真似事もしてるの\n病気になったら診てあげるわ", "実験が趣味の危険な科学者", 166, 27, 0, "ヒューマン", 7, "ミツキ（オーエド）", 53, "三石琴乃");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (117601, "AB", "鏡で自分を見ること", "ヴァイスフリューゲル　ランドソル支部", 15, 10, "ボクって本当に美しいなあ…\n可愛くて美しいなんて本当に罪だと思うけど\n生まれもったものだから仕方ないんだ♪", "ボクは誰よりも美しい", 150, 14, 0, "エルフ", 10, "ユキ（オーエド）", 40, "大空直美");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (117701, "A", "踊り、空手", "自警団（カォン）", 10, 7, "ハイターイ！　歌って踊って、\n最高に盛り上がるさ～！\nやさやさ、キミも一緒に踊るさ～！", "いつでも「なんくるないさ～」な天然娘", 158, 17, 0, "獣人族", 7, "カオリ（ハロウィン）", 53, "高森奈津美");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (117801, "O", "忍法開発", "ヴァイスフリューゲル　ランドソル支部", 15, 8, "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", "トーゴクの神秘、オシエテクダサイ！", 163, 16, 0, "ヒューマン", 31, "ニノン（ハロウィン）", 51, "佐藤聡美");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (117901, "O", "ファッション", "ルーセント学院", 14, 4, "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", "天真爛漫で人気者のカリスマモデル", 167, 17, 0, "魔族", 10, "スズナ（ハロウィン）", 48, "上坂すみれ");
