INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (119101, "AB", "小説を読むこと", "ヴァイスフリューゲル　ランドソル支部", 15, 11, "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", "妄想大好き！　ほんとは照れ屋な女の子", 157, 18, 0, "ヒューマン", 19, "クウカ（ノワール）", 49, "長妻樹里");
