INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (121901, "A", "小説執筆", "トワイライトキャラバン", 13, 7, "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！", "前世を信じる中二病患者、「疾風の冥姫」", 159, 17, 0, "魔族", 5, "アンナ（パイレーツ）", 45, "髙野麻美");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (122001, "AB", "占い", "悪魔偽王国軍（ディアボロス）", 7, 12, "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", "占いが得意な霊能少女", 157, 18, 0, "魔族", 22, "シノブ（パイレーツ）", 42, "大坪由佳");
