INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (122401, "A", "人助け、応援", "トゥインクルウィッシュ", 2, 8, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", "人助けが大好き！　前向き格闘娘", 155, 16, 0, "獣人族", 27, "ヒヨリ（サマー）", 44, "東山奈央");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (122501, "B", "読書、乗馬、お茶", "トゥインクルウィッシュ", 2, 1, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", "クールで何事にも真っ直ぐな剣士", 163, 18, 0, "魔族", 12, "レイ（サマー）", 46, "早見沙織");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (122601, "O", "料理、人間観察", "トゥインクルウィッシュ", 2, 4, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", "戦闘のサポートが得意な、心優しい少女", 158, 17, 0, "ヒューマン", 5, "ユイ（サマー）", 47, "種田梨沙");
