INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (127001, "AB", "小説を読むこと", "ヴァイスフリューゲル　ランドソル支部", 15, 11, "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", "妄想大好き！　ほんとは照れ屋な女の子", 157, 18, 0, "ヒューマン", 19, "クウカ（サマー）", 49, "長妻樹里");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (127101, "AB", "占い", "悪魔偽王国軍（ディアボロス）", 7, 12, "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", "占いが得意な霊能少女", 157, 18, 0, "魔族", 22, "シノブ（サマー）", 42, "大坪由佳");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (127201, "A", "猫と遊ぶ", "美食殿", 1, 9, "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", "行き倒れの謎のネコミミ魔法使い", 152, 14, 0, "獣人族", 2, "キャル（編入生）", 39, "立花理香");
