INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (928801, "B", "読書、乗馬、お茶", "トゥインクルウィッシュ", 17, 1, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", "クールで何事にも真っ直ぐな剣士", 163, 18, 0, "魔族", 12, "レイ（アストラル）", 46, "早見沙織");
